 1→export const VIEWS = { TOP: 'top', FRONT: 'front', SIDE: 'side' };
 2→
 3→export function getPartExtents(part) {
 4→  switch (part.type) {
 5→    case 'panel':
 6→      return { width: part.width, depth: part.depth, height: part.thickness };
 7→    case 'leg':
 8→      return { width: part.width, depth: part.depth, height: part.height };
 9→    case 'frame':
10→      return part.axis === 'y'
11→        ? { width: part.width, depth: part.length, height: part.height }
12→        : { width: part.length, depth: part.width, height: part.height };
13→    case 'cutout':
14→      return { width: part.width, depth: part.depth, height: part.height || part.depth };
15→    case 'hole':
16→      return { width: part.diameter, depth: part.diameter, height: part.depth };
17→    default:
18→      return { width: 0, depth: 0, height: 0 };
19→  }
20→}
21→
22→export function projectPartToView(part, view) {
23→  const ext = getPartExtents(part);
24→  const pos = part.position;
25→
26→  switch (view) {
27→    case 'top':
28→      return { svgX: pos.x, svgY: pos.y, svgWidth: ext.width, svgHeight: ext.depth };
29→    case 'front':
30→      return { svgX: pos.x, svgY: -(pos.z + ext.height), svgWidth: ext.width, svgHeight: ext.height };
31→    case 'side':
32→      return { svgX: pos.y, svgY: -(pos.z + ext.height), svgWidth: ext.depth, svgHeight: ext.height };
33→    default:
34→      return { svgX: pos.x, svgY: pos.y, svgWidth: ext.width, svgHeight: ext.depth };
35→  }
36→}
37→
38→export function viewToModelPosition(svgX, svgY, view, existingPosition = {}) {
39→  const pos = { x: existingPosition.x ?? 0, y: existingPosition.y ?? 0, z: existingPosition.z ?? 0 };
40→
41→  switch (view) {
42→    case 'top':
43→      return { ...pos, x: svgX, y: svgY };
44→    case 'front':
45→      return { ...pos, x: svgX, z: -svgY };
46→    case 'side':
47→      return { ...pos, y: svgX, z: -svgY };
48→    default:
49→      return { ...pos, x: svgX, y: svgY };
50→  }
51→}
52→
53→export function viewToModelExtents(svgW, svgH, view, partType) {
54→  const w = Math.abs(svgW);
55→  const h = Math.abs(svgH);
56→
57→  switch (view) {
58→    case 'top':
59→      if (partType === 'panel') return { width: w, depth: h };
60→      if (partType === 'leg') return { width: w, depth: h };
61→      if (partType === 'frame') return { length: w, width: h };
62→      return { width: w, depth: h };
63→    case 'front':
64→      if (partType === 'panel') return { width: w, thickness: h };
65→      if (partType === 'leg') return { width: w, height: h };
66→      if (partType === 'frame') return { length: w, height: h, width: 40 };
67→      return { width: w, height: h };
68→    case 'side':
69→      if (partType === 'panel') return { depth: w, thickness: h };
70→      if (partType === 'leg') return { depth: w, height: h };
71→      if (partType === 'frame') return { width: w, height: h, length: 500 };
72→      return { depth: w, height: h };
73→    default:
74→      return { width: w, depth: h };
75→  }
76→}
77→
78→export function getViewLabel(view) {
79→  switch (view) {
80→    case 'top': return 'Top (X\u2013Y)';
81→    case 'front': return 'Front (X\u2013Z)';
82→    case 'side': return 'Side (Y\u2013Z)';
83→    default: return view;
84→  }
85→}
