  3→export function projectDimensionPoint(point, view) {
  4→  switch (view) {
  5→    case 'top':
  6→      return { x: point.x, y: point.y };
  7→    case 'front':
  8→      return { x: point.x, y: -(point.z || 0) };
  9→    case 'side':
 10→      return { x: point.y, y: -(point.z || 0) };
