 1→function formatMm(value) {
 2→  return `${Math.round(value)} mm`;
 3→}
 4→
 5→export function getSketchPartInspection(project, selectedId) {
 6→  if (!selectedId) return null;
 7→
 8→  const part = project.parts.find((p) => p.id === selectedId);
 9→  if (!part) return null;
10→
11→  // Skip non-visible types
12→  if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') return null;
13→
14→  const title = part.name || `Part (${part.type})`;
15→  const assembly = part.assemblyId
16→    ? project.assemblies.find((a) => a.id === part.assemblyId)
17→    : null;
18→  const subtitle = assembly ? assembly.name : 'Unassigned';
19→
20→  const rows = [];
21→
22→  switch (part.type) {
23→    case 'panel':
24→      rows.push({ label: 'Width', value: formatMm(part.width) });
25→      rows.push({ label: 'Depth', value: formatMm(part.depth) });
26→      rows.push({ label: 'Thickness', value: formatMm(part.thickness) });
27→      break;
28→    case 'leg':
29→      rows.push({ label: 'Width', value: formatMm(part.width) });
30→      rows.push({ label: 'Depth', value: formatMm(part.depth) });
31→      rows.push({ label: 'Height', value: formatMm(part.height) });
32→      if (part.profile) rows.push({ label: 'Profile', value: part.profile });
33→      break;
34→    case 'frame':
35→      rows.push({ label: 'Length', value: formatMm(part.length) });
36→      rows.push({ label: 'Width', value: formatMm(part.width) });
37→      rows.push({ label: 'Height', value: formatMm(part.height) });
38→      if (part.axis) rows.push({ label: 'Axis', value: part.axis.toUpperCase() });
39→      break;
40→    default:
41→      if (part.width) rows.push({ label: 'Width', value: formatMm(part.width) });
42→      if (part.depth) rows.push({ label: 'Depth', value: formatMm(part.depth) });
43→      if (part.height) rows.push({ label: 'Height', value: formatMm(part.height) });
44→  }
45→
46→  return { id: part.id, title, subtitle, rows };
47→}
